export function deserialiseUBJSON(buf){let idx=0;if(buf[idx++]!==123)return null;const rootTree={};const workingSet=[rootTree];while(idx!==buf.length){let keyData;if(Array.isArray(workingSet[0])){if(buf[idx]===93){idx++;workingSet.shift();continue}}else{const controlCharacter=buf[idx++];if(controlCharacter===125){workingSet.shift();continue}if(controlCharacter!==105){throw new Error(`(ZB) Failed to find delimiter 1, found ${controlCharacter} instead at position ${idx}`)}const length=buf[idx++];keyData=buf.slice(idx,idx+length);idx+=length}const type=buf[idx++];let length=0;switch(type){case 123:{const leaf={};if(Array.isArray(workingSet[0])){workingSet[0].push(leaf)}else{workingSet[0][keyData.toString()]=leaf}workingSet.unshift(leaf);continue}case 91:{const leaf=[];if(Array.isArray(workingSet[0])){workingSet[0].push(leaf)}else{workingSet[0][keyData.toString()]=leaf}workingSet.unshift(leaf);continue}case 83:{if(buf[idx++]!==105){throw new Error("(ZB) Failed to find delimiter 2")}length=buf[idx++];break}case 100:{length=4;break}case 105:{length=1;break}case 85:{length=1;break}case 108:{length=4;break}case 76:{length=8;break}default:{throw new Error(`Unknown type ${type} at position ${idx}`)}}const valueData=buf.slice(idx,idx+length);let value;switch(type){case 83:{value=valueData.toString();break}case 100:{value=valueData.readFloatBE();break}case 105:{value=valueData.readInt8();break}case 85:{value=valueData.readUInt8();break}case 108:{value=valueData.readInt32BE();break}case 76:{value=valueData.readBigInt64BE();break}default:{value=valueData.toString()}}idx+=length;if(Array.isArray(workingSet[0])){workingSet[0].push(value)}else{workingSet[0][keyData.toString()]=value}}return rootTree}export default deserialiseUBJSON;